import React from "react";
import styled from "styled-components";

const ThemeChanged = styled.div`
  display: flex;
  justify-content: center;
  background-color: #fff;
  width: 20vw;
  p {
  text-align: center;
  }
`;

const ThemeChange = () => {
  return (
    <ThemeChanged>
      <p>Switch to Theme</p>
    </ThemeChanged>
  );
};

export default ThemeChange;
